//  This class implements a Node object in a Doubly Linked Structure.package DLSLists;public class LnrDblNd<T> {    private LnrDblNd<T> next;    private LnrDblNd<T> previous;    private T element;    public LnrDblNd() {       previous = null;       next = null;       element = null;    }    public LnrDblNd (T elem) {       previous = null;       next = null;       element = elem;    }    public LnrDblNd(LnrDblNd<T> prvs, LnrDblNd<T> nxt, T elem) {        previous = prvs;        next = nxt;        element = elem;    }    public LnrDblNd<T> getPrevious() {       return previous;    }    public void setPrevious (LnrDblNd<T> dlnode) {       previous = dlnode;    }        public LnrDblNd<T> getNext() {       return next;    }        public void setNext (LnrDblNd<T> dlnode) {       next = dlnode;    }        public T getElement() {       return element;    }    public void setElement (T elem) {       element = elem;    }    @Override    public String toString() {        String str= "", sprev="rfrnc", snext="rfrnc";        if (element == null) {            return "-sentinel node-";        } else {            if( previous == null) sprev= "null";            if( next == null) snext= "null";            str= "PREVIOUS: " + sprev + "  NEXT: "  + snext +                    "  ELEMENT: " + element.toString();         }        return str;    }    }